import{_ as t,c as p,o as e,a2 as r}from"./chunks/framework.CriqKoQt.js";const q=JSON.parse('{"title":"非技术思考笔记","description":"","frontmatter":{},"headers":[],"relativePath":"docs/2025下/note-no-tech-thought.md","filePath":"docs/2025下/note-no-tech-thought.md","lastUpdated":1774799326000}'),l={name:"docs/2025下/note-no-tech-thought.md"};function n(s,o,c,u,k,b){return e(),p("div",null,o[0]||(o[0]=[r('<div class="info custom-block"><p class="custom-block-title">作者</p><p>novlan1</p><p>2025.7.1</p></div><h1 id="非技术思考笔记" tabindex="-1">非技术思考笔记 <a class="header-anchor" href="#非技术思考笔记" aria-label="Permalink to &quot;非技术思考笔记&quot;">​</a></h1><hr><blockquote><p><strong>2025-12-31</strong> — 施舍，舔、迎合，表演，觉得自己掌控一切，垃圾，无能，运气。</p><p>施舍，舔、迎合，表演，觉得自己掌控一切，垃圾，无能，运气。</p></blockquote><hr><blockquote><p><strong>2025-12-30</strong> — 1. 每天必须留时间做自己的事</p><ol><li>每天必须留时间做自己的事</li><li>少说</li></ol></blockquote><hr><blockquote><p><strong>2025-12-29</strong> — 1. 虚伪，与真诚是反义词</p><ol><li>虚伪，与真诚是反义词</li><li>打工挣钱而已</li><li>大头兵而已</li></ol></blockquote><hr><blockquote><p><strong>2025-12-29</strong> — 1. 我必须拯救全世界，才能拿到和其他人相同的回报</p><ol><li>我必须拯救全世界，才能拿到和其他人相同的回报</li><li>技术没有与人的沟通重要</li><li>还是太舒适了，待在舒适区太久太久太久太久太久了</li></ol></blockquote><hr><blockquote><p><strong>2025-12-29</strong> — 财富就是知识，为啥要把财富给别人呢，所积累的、记录的这些…</p><p>财富就是知识，为啥要把财富给别人呢，所积累的、记录的这些都是财富啊。</p></blockquote><hr><blockquote><p><strong>2025-12-27</strong> — 与别人争论有好处，除了那种纯抬扛的，你可以多个角度看问题…</p><p>与别人争论有好处，除了那种纯抬扛的，你可以多个角度看问题，思路变宽，思考变深，在答辩、写文章中都有用。</p></blockquote><hr><blockquote><p><strong>2025-12-27</strong> — 每次 v2 都要问问为什么，改动了什么 breaking…</p><p>每次 v2 都要问问为什么，改动了什么 breaking 的、不能兼容的，记录下，避免重复起跑。</p></blockquote><hr><blockquote><p><strong>2025-12-15</strong> — 【盲评】这是一个基于pnpm 的工具集仓库，提供Vite…</p><p>【盲评】这是一个基于pnpm 的工具集仓库，提供Vite插件、Webpack 插件、Webpack Loader、ESLint插件、ESlint公共配置、项目公共配置等内容。</p></blockquote><hr><blockquote><p><strong>2025-12-12</strong> — 记性越来越差了， 这种命令都要回忆下了。</p><p>记性越来越差了，<code>npx eslint --ext .ts,.js,.vue . --quiet --fix</code> 这种命令都要回忆下了。</p></blockquote><hr><blockquote><p><strong>2025-12-12</strong> — 家庭，能力，啥也没有</p><p>家庭，能力，啥也没有</p></blockquote><hr><blockquote><p><strong>2025-12-10</strong> — 图腾，忠实拥趸。</p><p>图腾，忠实拥趸。</p><p>留一点净土吧。</p><p>这是当时写 tdesign-uniapp 时的信念。</p></blockquote><hr><blockquote><p><strong>2025-12-10</strong> — 外表单纯，内心蛇蝎。</p><p>外表单纯，内心蛇蝎。</p><p>我见过太多了。</p></blockquote><hr><blockquote><p><strong>2025-12-10</strong> — 等价交换？</p><p>等价交换？</p><p>真正的x是不得？</p><p>博爱是爱吗？</p><p>真正对你好的人？</p><p>本质是找对你好的人，而对你好的人和伤害你的人，是两类人。</p></blockquote><hr><blockquote><p><strong>2025-12-10</strong> — 不用帮别人，没啥交情，普通同事，一离职啥也不是。</p><p>不用帮别人，没啥交情，普通同事，一离职啥也不是。</p><p>天坑，拉你一起跳坑。</p></blockquote><hr><blockquote><p><strong>2025-12-10</strong> — 回忆都是不全的，没必要了，只记得好的一方面，忘记自己多么…</p><p>回忆都是不全的，没必要了，只记得好的一方面，忘记自己多么蠢了吗，忘记自己家庭是什么样了吗</p><p>当我回忆年轻时的遗憾时。</p></blockquote><hr><blockquote><p><strong>2025-12-10</strong> — 拼命打压、贬低、否定你，对这个要有预期。</p><p>拼命打压、贬低、否定你，对这个要有预期。</p></blockquote><hr><blockquote><p><strong>2025-12-10</strong> — 慢就是稳，稳就是快？前提是别太慢。</p><p>慢就是稳，稳就是快？前提是别太慢。</p></blockquote><hr><blockquote><p><strong>2025-12-10</strong> — 代码写的像屎一样，连及早返回都不知道。</p><p>代码写的像屎一样，连及早返回都不知道。</p><p>不懂项目框架，不懂技术原理，遇到问题就会艾特人，不知道怎么做技术负责人。也不懂向下兼容，就瞎改。就知道抢着发言，搞得像懂很多一样。</p></blockquote><hr><blockquote><p><strong>2025-12-09</strong> — 真的要跟他们一样平庸吗？甚至不如他们吗？</p><p>真的要跟他们一样平庸吗？甚至不如他们吗？</p></blockquote><hr><blockquote><p><strong>2025-12-09</strong> — 所有人都想打倒你，踩扁你！</p><p>所有人都想打倒你，踩扁你！</p></blockquote><hr><blockquote><p><strong>2025-12-09</strong> — 方向不对，走再多也是没用。浪费时间，多花时间重来！</p><p>方向不对，走再多也是没用。浪费时间，多花时间重来！</p></blockquote><hr><blockquote><p><strong>2025-12-08</strong> — 写了个页面，专门用来记录感想和笔记。</p><p>写了个页面，专门用来记录感想和笔记。</p><p>再也不用从备忘录里转存了。</p><p>很简单，很实用，提高效率。</p></blockquote><hr><blockquote><p><strong>2025-12-08</strong> — 热闹是他们的，我什么也没有。付出与收获不对等？</p><p>热闹是他们的，我什么也没有。付出与收获不对等？</p></blockquote><hr><blockquote><p><strong>2025-12-08</strong> — 定制化和复用性是反义词</p><p>定制化和复用性是反义词</p></blockquote><hr><blockquote><p><strong>2025-12-08</strong> — 又装又菜</p><p>又装又菜</p></blockquote>',52)]))}